function DragEditor({ onClose, modules, setModules }: { onClose: () => void; modules: ModuleType[]; setModules: React.Dispatch<React.SetStateAction<ModuleType[]>> }) {
  const [draggedItem, setDraggedItem] = useState<ModuleType | null>(null);

  const moduleLabels: Record<ModuleType, string> = {
    carousel: '图片轮播',
    notifications: '通知公告',
    resources: '热门课程',
    personal: '个人空间',
    external: '外部系统',
  };

  const handleDragStart = (e: React.DragEvent, module: ModuleType) => {
    setDraggedItem(module);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetModule: ModuleType) => {
    e.preventDefault();
    if (draggedItem && draggedItem !== targetModule) {
      const newModules = [...modules];
      const draggedIndex = newModules.indexOf(draggedItem);
      const targetIndex = newModules.indexOf(targetModule);
      newModules.splice(draggedIndex, 1);
      newModules.splice(targetIndex, 0, draggedItem);
      setModules(newModules);
    }
    setDraggedItem(null);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />
      <div className="relative glass-card w-full max-w-lg p-6 rounded-2xl">
        <div className="flex items-center justify-between mb-6">
          <h3 className="text-xl font-bold text-white flex items-center gap-2">
            <Edit3 className="w-5 h-5 text-secondary-400" />
            门户可视化配置
          </h3>
          <button onClick={onClose} className="p-2 rounded-lg hover:bg-white/10 text-gray-400 hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <p className="text-gray-400 text-sm mb-6">拖拽模块调整页面布局顺序</p>

        <div className="space-y-3">
          {modules.map((module) => (
            <div
              key={module}
              draggable
              onDragStart={(e) => handleDragStart(e, module)}
              onDragOver={handleDragOver}
              onDrop={(e) => handleDrop(e, module)}
              className={`flex items-center gap-4 p-4 rounded-xl transition-all duration-300 ${
                draggedItem === module ? 'opacity-50 scale-95' : 'hover:bg-white/10'
              }`}
              style={{ backgroundColor: draggedItem && draggedItem !== module ? 'rgba(157, 127, 221, 0.1)' : undefined }}
            >
              <div className="w-10 h-10 rounded-lg bg-white/10 flex items-center justify-center text-gray-400">
                <GripVertical className="w-5 h-5" />
              </div>
              <div className="flex-1">
                <p className="text-white font-medium">{moduleLabels[module]}</p>
              </div>
              <LayoutGrid className="w-5 h-5 text-gray-500" />
            </div>
          ))}
        </div>

        <div className="flex gap-3 mt-6">
          <button onClick={onClose} className="flex-1 py-2.5 rounded-xl bg-white/5 text-gray-400 hover:text-white hover:bg-white/10 transition-colors">
            取消
          </button>
          <button 
            onClick={onClose}
            className="flex-1 py-2.5 rounded-xl bg-gradient-to-r from-secondary-400 to-primary-600 text-white font-medium hover:shadow-lg hover:shadow-purple-500/30 transition-all"
          >
            保存配置
          </button>
        </div>
      </div>
    </div>
  );
}

