function ImportModal({ onClose }: { onClose: () => void }) {
  const [selectedCourses, setSelectedCourses] = useState<string[]>([]);

  const courses = [
    { id: '1', name: '高等数学', chapters: 12 },
    { id: '2', name: '计算机基础', chapters: 8 },
    { id: '3', name: '大学物理', chapters: 10 },
    { id: '4', name: '线性代数', chapters: 6 },
  ];

  const toggleCourse = (id: string) => {
    setSelectedCourses(prev => prev.includes(id) ? prev.filter(c => c !== id) : [...prev, id]);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />
      <div className="relative glass-card w-full max-w-lg p-6 rounded-2xl">
        <div className="flex items-center justify-between mb-6">
          <h3 className="text-xl font-bold text-white">导入课程内容</h3>
          <button onClick={onClose} className="p-2 rounded-lg hover:bg-white/10 text-gray-400 hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="space-y-3 mb-6">
          {courses.map((course) => (
            <div 
              key={course.id}
              onClick={() => toggleCourse(course.id)}
              className={`flex items-center gap-4 p-4 rounded-xl cursor-pointer transition-all ${
                selectedCourses.includes(course.id) 
                  ? 'bg-secondary-400/20 border border-secondary-400/50' 
                  : 'bg-white/5 hover:bg-white/10'
              }`}
            >
              <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${
                selectedCourses.includes(course.id) 
                  ? 'bg-secondary-400 border-secondary-400' 
                  : 'border-gray-500'
              }`}>
                {selectedCourses.includes(course.id) && <CheckCircle2 className="w-4 h-4 text-white" />}
              </div>
              <div className="flex-1">
                <p className="text-white font-medium">{course.name}</p>
                <p className="text-gray-500 text-xs">{course.chapters}个章节</p>
              </div>
              <ChevronRight className="w-5 h-5 text-gray-400" />
            </div>
          ))}
        </div>

        <div className="flex gap-3">
          <button onClick={onClose} className="flex-1 py-2.5 rounded-xl bg-white/5 text-gray-400 hover:text-white hover:bg-white/10 transition-colors">
            取消
          </button>
          <button 
            onClick={() => { onClose(); alert('已导入选中课程的章节内容！'); }}
            className="flex-1 py-2.5 rounded-xl bg-gradient-to-r from-secondary-400 to-primary-600 text-white font-medium"
          >
            确认导入
          </button>
        </div>
      </div>
    </div>
  );
}

