import { BrowserRouter as Router, Routes, Route, Navigate, useLocation } from "react-router-dom";
import { useEffect } from "react";
import { useStore } from "./store/useStore";
import Login from "./pages/Login";
import Dashboard from "./pages/Dashboard";
import Teaching from "./pages/Teaching";
import Exam from "./pages/Exam";
import Training from "./pages/Training";
import Portal from "./pages/Portal";
import Expand from "./pages/Expand";
import Layout from "./components/Layout";

function ProtectedRoute({ children }: { children: React.ReactNode }) {
  const isLoggedIn = useStore((state) => state.isLoggedIn);
  if (!isLoggedIn) {
    return <Navigate to="/login" />;
  }
  return <>{children}</>;
}

function PublicRoute({ children }: { children: React.ReactNode }) {
  const isLoggedIn = useStore((state) => state.isLoggedIn);
  if (isLoggedIn) {
    const lastPath = localStorage.getItem('trae_lastPath') || '/';
    return <Navigate to={lastPath} />;
  }
  return <>{children}</>;
}

function AdminProtectedRoute({ children }: { children: React.ReactNode }) {
  const isLoggedIn = useStore((state) => state.isLoggedIn);
  const user = useStore((state) => state.user);
  if (!isLoggedIn) {
    return <Navigate to="/login" />;
  }
  if (user?.role !== 'admin') {
    return <Navigate to="/" />;
  }
  return <>{children}</>;
}

function TeacherProtectedRoute({ children }: { children: React.ReactNode }) {
  const isLoggedIn = useStore((state) => state.isLoggedIn);
  const user = useStore((state) => state.user);
  if (!isLoggedIn) {
    return <Navigate to="/login" />;
  }
  if (user?.role === 'student') {
    return <Navigate to="/" />;
  }
  return <>{children}</>;
}

function RouteTracker() {
  const location = useLocation();
  const isLoggedIn = useStore((state) => state.isLoggedIn);

  useEffect(() => {
    if (isLoggedIn && location.pathname !== '/login') {
      localStorage.setItem('trae_lastPath', location.pathname + location.search + location.hash);
    }
  }, [location, isLoggedIn]);

  return null;
}

export default function App() {
  return (
    <Router>
      <RouteTracker />
      <Routes>
        <Route
          path="/login"
          element={
            <PublicRoute>
              <Login />
            </PublicRoute>
          }
        />
        <Route
          path="/"
          element={
            <ProtectedRoute>
              <Layout>
                <Portal />
              </Layout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/dashboard"
          element={
            <ProtectedRoute>
              <Layout>
                <Dashboard />
              </Layout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/teaching"
          element={
            <ProtectedRoute>
              <Layout>
                <Teaching />
              </Layout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/exam"
          element={
            <ProtectedRoute>
              <Layout>
                <Exam />
              </Layout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/training"
          element={
            <AdminProtectedRoute>
              <Layout>
                <Training />
              </Layout>
            </AdminProtectedRoute>
          }
        />
        <Route
          path="/expand"
          element={
            <TeacherProtectedRoute>
              <Layout>
                <Expand />
              </Layout>
            </TeacherProtectedRoute>
          }
        />
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </Router>
  );
}
